+        .or_else(|| value.as_i64().and_then(|n| u64::try_from(n).ok()))
+        .or_else(|| {
+            value.as_f64().and_then(|n| {
+                if n.is_finite() && n >= 0.0 && n.fract() == 0.0 {
+                    Some(n as u64)
+                } else {
+                    None
+                }
+            })
+        })
+}
